import{c as t,Q as a,j as i,m as r}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse(`{"title":"Fat Skills, Thin Harness: The Framework I'm Using to Ship a Tech Grant in Ten Working Days","description":"","frontmatter":{"url":"https://www.testventures.net/blog/fat-skills-thin-harness","title":"Fat Skills, Thin Harness: The Framework I'm Using to Ship a Tech Grant in Ten Working Days","author":"Geordie (TestVentures/Powered by Finn)","date":"2026-04-14T00:00:00.000Z","status":"SUCCESS"},"headers":[],"relativePath":"research/ai-articles/43-testventures-fat-skills-thin-harness.md","filePath":"research/ai-articles/43-testventures-fat-skills-thin-harness.md","lastUpdated":1779894392000}`),n={name:"research/ai-articles/43-testventures-fat-skills-thin-harness.md"};function s(o,e,l,h,d,c){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="fat-skills-thin-harness-the-framework-i-m-using-to-ship-a-tech-grant-in-ten-working-days" tabindex="-1">Fat Skills, Thin Harness: The Framework I&#39;m Using to Ship a Tech Grant in Ten Working Days <a class="header-anchor" href="#fat-skills-thin-harness-the-framework-i-m-using-to-ship-a-tech-grant-in-ten-working-days" aria-label="Permalink to &quot;Fat Skills, Thin Harness: The Framework I&#39;m Using to Ship a Tech Grant in Ten Working Days&quot;">​</a></h1><p>A week ago, Y Combinator CEO Garry Tan published &quot;Thin Harness, Fat Skills,&quot; advocating a three-layer architectural approach: encode human judgment into markdown procedures, push deterministic work into proven code, and maintain a minimal software layer between them.</p><h2 id="understanding-tan-s-framework" tabindex="-1">Understanding Tan&#39;s Framework <a class="header-anchor" href="#understanding-tan-s-framework" aria-label="Permalink to &quot;Understanding Tan&#39;s Framework&quot;">​</a></h2><p>The bottleneck in AI work isn&#39;t model intelligence—it&#39;s whether the model understands your specific schema, data conventions, and domain expertise.</p><h3 id="the-three-layer-stack" tabindex="-1">The Three-Layer Stack <a class="header-anchor" href="#the-three-layer-stack" aria-label="Permalink to &quot;The Three-Layer Stack&quot;">​</a></h3><ol><li><p><strong>Fat skills (top):</strong> Markdown playbooks encoding procedures and judgment specific to your operations. These capture &quot;how we do things here&quot; and represent 90% of the value.</p></li><li><p><strong>Thin harness (middle):</strong> Minimal plumbing that runs the model and handles file I/O. Most teams overbuild this layer unnecessarily.</p></li><li><p><strong>Fat code (bottom):</strong> Battle-tested, existing software for deterministic work requiring exactness—payments, authentication, database operations.</p></li></ol><h2 id="why-this-matters-for-non-developers" tabindex="-1">Why This Matters for Non-Developers <a class="header-anchor" href="#why-this-matters-for-non-developers" aria-label="Permalink to &quot;Why This Matters for Non-Developers&quot;">​</a></h2><p>&quot;Your work with AI isn&#39;t what you say in one conversation. It&#39;s the set of skills—the markdown playbooks—that you accumulate&quot; over time. These become your durable assets, regardless of which model you use.</p><p>For small operators, the leverage formula is:</p><ul><li>Your judgment written as procedures</li><li>One functional harness</li><li>Delegated work to existing, proven software</li></ul><h2 id="the-charity-infrastructure-project-example" tabindex="-1">The Charity Infrastructure Project Example <a class="header-anchor" href="#the-charity-infrastructure-project-example" aria-label="Permalink to &quot;The Charity Infrastructure Project Example&quot;">​</a></h2><p>The author mapped a charity donation platform onto this framework:</p><h3 id="fat-skills-identified-nine-judgment-calls" tabindex="-1">Fat Skills Identified (Nine Judgment Calls) <a class="header-anchor" href="#fat-skills-identified-nine-judgment-calls" aria-label="Permalink to &quot;Fat Skills Identified (Nine Judgment Calls)&quot;">​</a></h3><ul><li>Onboarding charities</li><li>Generating jurisdiction-specific briefs</li><li>Interpreting donor intent</li><li>Vetting organizations</li><li>Recording demos</li><li>CEO-style document review</li><li>Writing impact stories</li><li>Charity database searches</li><li>Preparing for funder convenings</li></ul><h3 id="fat-code-layer" tabindex="-1">Fat Code Layer <a class="header-anchor" href="#fat-code-layer" aria-label="Permalink to &quot;Fat Code Layer&quot;">​</a></h3><p>Rather than building backend infrastructure, the author sourced existing solutions for payments, verification, and record-keeping.</p><h3 id="thin-harness" tabindex="-1">Thin Harness <a class="header-anchor" href="#thin-harness" aria-label="Permalink to &quot;Thin Harness&quot;">​</a></h3><p>A small server, single payment endpoint, simple database, donation page, basic dashboard—nothing more.</p><p>This approach allowed shipping a working prototype with real transactions in 48 hours.</p><h2 id="eight-point-self-learning-practice" tabindex="-1">Eight-Point Self-Learning Practice <a class="header-anchor" href="#eight-point-self-learning-practice" aria-label="Permalink to &quot;Eight-Point Self-Learning Practice&quot;">​</a></h2><ol><li><strong>Write skills during work, not after</strong>—capture details only visible in real contexts</li><li><strong>Edit procedures, not outputs</strong>—fix the rule to compound improvements</li><li><strong>Test new skills three times</strong> before considering them reliable</li><li><strong>Maintain a skills changelog</strong> with dated edits and rationale</li><li><strong>Study external skill packs weekly</strong> for patterns to adapt</li><li><strong>Run monthly skill reviews</strong> pruning unused and overlapping procedures</li><li><strong>Search for existing solutions before building</strong> deterministic systems</li><li><strong>Keep skills model-agnostic</strong>—write for generalist readers, not specific LLM quirks</li></ol><h2 id="core-insight" tabindex="-1">Core Insight <a class="header-anchor" href="#core-insight" aria-label="Permalink to &quot;Core Insight&quot;">​</a></h2><p>&quot;The loop is a commodity. The skills are the compounding asset. The fat code is leverage you didn&#39;t have to build.&quot; Model churn happens every few weeks; skills remain constant. The judgment you document becomes your actual competitive advantage.</p>',23)])])}const g=t(n,[["render",s]]);export{p as __pageData,g as default};
